SELECT

FROM mall_order_info mall_order_info

	
		AND mall_order_info.`user_id` = #{query.userId}
	
	
		
			AND mall_order_info.`is_pay` = '0'
			AND mall_order_info.`status` is null
		
		
			AND mall_order_info.`status` = '3'
		
		
			AND mall_order_info.`status` = #{query.status}
		
	
	
		AND mall_order_info.`order_no` = #{query.orderNo}

SELECT

FROM mall_order_info mall_order_info
WHERE mall_order_info.`id` = #{id}
